// Code - Validate, Price & Decide Stage
// LANDOC Marriage Registration V2 - Safe validated version
// Purpose:
// 1. Parse AI output safely
// 2. Preserve Data Table session_data
// 3. Support both old and new session_data formats
// 4. Validate only when required
// 5. Move correctly to cost confirmation, lead creation, payment, and document collection

const rawInput = $input.first().json || {};

// Try to read original inbound context from service trigger/debug node
let inbound = {};
try {
  inbound = $('SET_Debug_Inbound_Context').item.json || {};
} catch (e) {
  inbound = {};
}

// --------------------------------------------------
// Helpers
// --------------------------------------------------

function isObject(value) {
  return value && typeof value === 'object' && !Array.isArray(value);
}

function parseMaybeJson(value) {
  if (!value) return {};

  if (isObject(value)) return value;

  if (typeof value !== 'string') return {};

  let cleaned = value
    .trim()
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/```$/i, '')
    .trim();

  try {
    const parsed = JSON.parse(cleaned);
    return isObject(parsed) ? parsed : {};
  } catch (e) {
    return {};
  }
}

function pick(...values) {
  for (const value of values) {
    if (value !== undefined && value !== null && String(value).trim() !== '') {
      return value;
    }
  }
  return '';
}

function toBool(value) {
  return value === true || value === 'true';
}

function normalizeMobile(value) {
  return String(value || '').replace(/\D/g, '').slice(-10);
}

function isValidMobile(value) {
  return /^[6-9]\d{9}$/.test(String(value || '').trim());
}

function isValidDateFormat(value) {
  return /^\d{2}\/\d{2}\/\d{4}$/.test(String(value || '').trim());
}

function parseDDMMYYYY(dateStr) {
  if (!isValidDateFormat(dateStr)) return null;

  const [dd, mm, yyyy] = String(dateStr).split('/').map(Number);
  const d = new Date(yyyy, mm - 1, dd);

  if (
    d.getFullYear() !== yyyy ||
    d.getMonth() !== mm - 1 ||
    d.getDate() !== dd
  ) {
    return null;
  }

  return d;
}

function calculateAge(dob) {
  const d = parseDDMMYYYY(dob);
  if (!d) return null;

  const today = new Date();
  let age = today.getFullYear() - d.getFullYear();
  const m = today.getMonth() - d.getMonth();

  if (m < 0 || (m === 0 && today.getDate() < d.getDate())) {
    age--;
  }

  return age;
}

function marriageAgeDays(marriageDate) {
  const d = parseDDMMYYYY(marriageDate);
  if (!d) return null;

  const today = new Date();
  const diffMs = today.getTime() - d.getTime();
  return Math.floor(diffMs / (1000 * 60 * 60 * 24));
}

function normalizeReligion(value) {
  const v = String(value || '').trim().toLowerCase();

  if (v === '1' || v.includes('hindu')) return 'Hindu';
  if (v === '2' || v.includes('muslim')) return 'Muslim';
  if (v === '3' || v.includes('christian')) return 'Christian';
  if (v === '4' || v.includes('other')) return 'Other';

  if (v === 'islam') return 'Muslim';

  return String(value || '').trim();
}

function getServiceCategory(brideReligion, groomReligion) {
  const bride = normalizeReligion(brideReligion);
  const groom = normalizeReligion(groomReligion);

  if (bride === 'Hindu' && groom === 'Hindu') return 'Hindu Marriage';
  if (bride === 'Muslim' && groom === 'Muslim') return 'Muslim Marriage';
  if (bride === 'Christian' && groom === 'Christian') return 'Christian Marriage';
  if (bride && groom && bride !== groom) return 'Special Marriage';

  return 'Need Team Verification';
}

function getServiceCost(marriageDate) {
  const days = marriageAgeDays(marriageDate);
  const cost = days !== null && days > 150 ? 7500 : 6000;
  return {
    cost,
    formatted: `₹${cost.toLocaleString('en-IN')}`,
    days_from_marriage: days,
    exceeds_150_days: days !== null && days > 150
  };
}

function replyByLanguage(language, english, tamil, tanglish) {
  if (language === 'Tamil') return tamil;
  if (language === 'Tanglish') return tanglish;
  return english;
}

// --------------------------------------------------
// Parse AI output and session data
// --------------------------------------------------

const aiParsed = parseMaybeJson(rawInput.output || rawInput.text || rawInput.reply);
const input = {
  ...inbound,
  ...rawInput,
  ...aiParsed
};

const sessionData = parseMaybeJson(
  input.session_data ||
  inbound.session_data ||
  aiParsed.session_data
);

const nestedSessionData = parseMaybeJson(sessionData.session_data);

// Merge nested session if any accidental nesting happened
const s = {
  ...sessionData,
  ...nestedSessionData
};

const message = String(inbound.message || input.message || '').trim();
const lowerMessage = message.toLowerCase();

const language = pick(input.language, inbound.language, s.language, 'English');

// --------------------------------------------------
// Normalize all collected data
// Supports both:
// customer.name and customer_details.customer_name
// bride.dob and bride_details.bride_dob
// --------------------------------------------------

const customer = {
  name: pick(
    input.customer?.name,
    input.customer_name,
    input.customer_details?.customer_name,
    s.customer?.name,
    s.customer_details?.customer_name
  ),
  mobile: normalizeMobile(pick(
    input.customer?.mobile,
    input.customer_mobile,
    input.customer_details?.customer_mobile,
    s.customer?.mobile,
    s.customer_details?.customer_mobile
  ))
};

const bride = {
  name: pick(
    input.bride?.name,
    input.bride_name,
    input.bride_details?.bride_name,
    s.bride?.name,
    s.bride_details?.bride_name
  ),
  dob: pick(
    input.bride?.dob,
    input.bride_dob,
    input.bride_details?.bride_dob,
    s.bride?.dob,
    s.bride_details?.bride_dob
  ),
  religion: normalizeReligion(pick(
    input.bride?.religion,
    input.bride_religion,
    input.bride_details?.bride_religion,
    s.bride?.religion,
    s.bride_details?.bride_religion
  )),
  address: pick(
    input.bride?.address,
    input.bride_address,
    input.bride_details?.bride_address,
    s.bride?.address,
    s.bride_details?.bride_address
  )
};

const groom = {
  name: pick(
    input.groom?.name,
    input.groom_name,
    input.groom_details?.groom_name,
    s.groom?.name,
    s.groom_details?.groom_name
  ),
  dob: pick(
    input.groom?.dob,
    input.groom_dob,
    input.groom_details?.groom_dob,
    s.groom?.dob,
    s.groom_details?.groom_dob
  ),
  religion: normalizeReligion(pick(
    input.groom?.religion,
    input.groom_religion,
    input.groom_details?.groom_religion,
    s.groom?.religion,
    s.groom_details?.groom_religion
  )),
  address: pick(
    input.groom?.address,
    input.groom_address,
    input.groom_details?.groom_address,
    s.groom?.address,
    s.groom_details?.groom_address
  )
};

const marriage = {
  marriage_date: pick(
    input.marriage?.marriage_date,
    input.marriage_date,
    input.marriage_details?.marriage_date,
    s.marriage?.marriage_date,
    s.marriage_details?.marriage_date
  ),
  marriage_place: pick(
    input.marriage?.marriage_place,
    input.marriage_place,
    input.marriage_details?.marriage_place,
    s.marriage?.marriage_place,
    s.marriage_details?.marriage_place
  )
};

const brideAge = calculateAge(bride.dob);
const groomAge = calculateAge(groom.dob);
const serviceCategory = getServiceCategory(bride.religion, groom.religion);
const serviceCost = getServiceCost(marriage.marriage_date);

let selectedServiceOption = pick(
  input.selected_service_option,
  input.service_details?.selected_service_option,
  s.selected_service_option,
  s.service_details?.selected_service_option
);

let calculatedServiceName = pick(
  input.calculated_service_name,
  input.service_details?.calculated_service_name,
  s.calculated_service_name,
  s.service_details?.calculated_service_name,
  `${serviceCategory} LANDOC Service`
);

let calculatedServiceCost = pick(
  input.calculated_service_cost,
  input.service_details?.calculated_service_cost,
  s.calculated_service_cost,
  s.service_details?.calculated_service_cost,
  serviceCost.formatted
);

// --------------------------------------------------
// Build base result
// --------------------------------------------------

let currentStage = pick(
  input.current_stage,
  inbound.current_stage,
  s.current_stage,
  'start'
);

let reply = pick(
  input.reply,
  input.output,
  input.chatbot_reply,
  input.last_reply,
  ''
);

let result = {
  ...input,

  output: reply,
  reply,
  chatbot_reply: reply,
  last_reply: reply,

  active_service: 'marriage_registration',
  source: input.source || 'odoo_chatbot',
  status: input.status || '',
  language,

  current_stage: currentStage,

  main_menu_selected: input.main_menu_selected || '',
  intent: input.intent || '',

  service_category: serviceCategory,
  service_name: serviceCategory,
  selected_service_option: selectedServiceOption,
  selected_service_option_backend: input.selected_service_option_backend || selectedServiceOption || '',
  selected_service_option_label: input.selected_service_option_label || selectedServiceOption || '',
  selected_cost: serviceCost.cost,
  cost_shown: toBool(input.cost_shown) || toBool(s.cost_shown) || toBool(s.confirmation_details?.cost_shown),

  calculated_service_name: calculatedServiceName,
  calculated_service_cost: calculatedServiceCost,

  ticket_status_requested: false,
  ticket_reference: '',
  ticket_mobile: '',
  ready_to_fetch_ticket_status: false,

  customer_confirmed: toBool(input.customer_confirmed) || toBool(s.customer_confirmed) || toBool(s.confirmation_details?.customer_confirmed),
  correction_requested: toBool(input.correction_requested) || toBool(s.correction_requested) || toBool(s.confirmation_details?.correction_requested),

  hindu_option_required: serviceCategory === 'Hindu Marriage' && !selectedServiceOption,
  hindu_option_selected: serviceCategory === 'Hindu Marriage' && !!selectedServiceOption,

  proceed_confirmed: toBool(input.proceed_confirmed) || toBool(s.proceed_confirmed) || toBool(s.confirmation_details?.proceed_confirmed),

  not_interested: toBool(input.not_interested) || toBool(s.not_interested),
  not_interested_reason: pick(input.not_interested_reason, s.not_interested_reason),

  customer,
  bride,
  groom,
  marriage,

  ready_to_create_lead: toBool(input.ready_to_create_lead),
  lead_creation_required: toBool(input.lead_creation_required),
  lead_created: toBool(input.lead_created) || toBool(s.lead_created) || toBool(s.lead_details?.lead_created),
  lead_creation_status: input.lead_creation_status || '',
  odoo_lead_id: pick(input.odoo_lead_id, s.odoo_lead_id, s.lead_details?.odoo_lead_id),
  odoo_ticket_reference: input.odoo_ticket_reference || '',
  lead_payload_ready: toBool(input.lead_payload_ready),

  payment_required: toBool(input.payment_required) || toBool(s.payment_required) || toBool(s.payment_details?.payment_required),
  payment_stage: pick(input.payment_stage, s.payment_stage, s.payment_details?.payment_stage),
  payment_status: pick(input.payment_status, s.payment_status, s.payment_details?.payment_status),
  advance_percentage_requested: pick(input.advance_percentage_requested, s.advance_percentage_requested, s.payment_details?.advance_percentage_requested),
  advance_amount_requested: pick(input.advance_amount_requested, s.advance_amount_requested, s.payment_details?.advance_amount_requested),
  amount_paid: pick(input.amount_paid, s.amount_paid, s.payment_details?.amount_paid),
  payment_screenshot_received: toBool(input.payment_screenshot_received) || toBool(s.payment_screenshot_received) || toBool(s.payment_details?.payment_screenshot_received),
  payment_screenshot_url: pick(input.payment_screenshot_url, s.payment_screenshot_url, s.payment_details?.payment_screenshot_url),
  payment_pending_amount: pick(input.payment_pending_amount, s.payment_pending_amount, s.payment_details?.payment_pending_amount),
  customer_refused_payment: toBool(input.customer_refused_payment) || toBool(s.customer_refused_payment) || toBool(s.payment_details?.customer_refused_payment),
  payment_note: pick(input.payment_note, s.payment_note, s.payment_details?.payment_note),

  documents_status: pick(input.documents_status, s.documents_status, s.document_details?.documents_status),
  documents_collected: toBool(input.documents_collected) || toBool(s.documents_collected) || toBool(s.document_details?.documents_collected),
  additional_documents_required: toBool(input.additional_documents_required) || toBool(s.additional_documents_required) || toBool(s.document_details?.additional_documents_required),
  additional_document_list: input.additional_document_list || s.additional_document_list || s.document_details?.additional_document_list || [],

  close_session: toBool(input.close_session)
};

// --------------------------------------------------
// Mandatory validation helper
// --------------------------------------------------

function getMissingMandatoryFields() {
  const missing = [];

  if (!customer.name) missing.push('Customer name');
  if (!customer.mobile || !isValidMobile(customer.mobile)) missing.push('Customer mobile');

  if (!bride.name) missing.push('Bride name');
  if (!bride.dob || !isValidDateFormat(bride.dob)) missing.push('Bride DOB');
  if (!bride.religion) missing.push('Bride religion');
  if (!bride.address) missing.push('Bride address');

  if (!groom.name) missing.push('Groom name');
  if (!groom.dob || !isValidDateFormat(groom.dob)) missing.push('Groom DOB');
  if (!groom.religion) missing.push('Groom religion');
  if (!groom.address) missing.push('Groom address');

  if (!marriage.marriage_date || !isValidDateFormat(marriage.marriage_date)) missing.push('Marriage date');
  if (!marriage.marriage_place) missing.push('Marriage place');

  return missing;
}

function stageForMissingField(field) {
  const map = {
    'Customer name': 'collect_customer_name',
    'Customer mobile': 'collect_customer_mobile',
    'Bride name': 'collect_bride_name',
    'Bride DOB': 'collect_bride_dob',
    'Bride religion': 'collect_bride_religion',
    'Bride address': 'collect_bride_address',
    'Groom name': 'collect_groom_name',
    'Groom DOB': 'collect_groom_dob',
    'Groom religion': 'collect_groom_religion',
    'Groom address': 'collect_groom_address',
    'Marriage date': 'collect_marriage_date',
    'Marriage place': 'collect_marriage_place'
  };

  return map[field] || 'collect_customer_name';
}

function questionForMissingField(field) {
  const map = {
    'Customer name': 'Please provide your name.',
    'Customer mobile': 'Please provide a valid 10-digit mobile number.',
    'Bride name': "Please tell me the bride's name.",
    'Bride DOB': "Please provide the bride's DOB in DD/MM/YYYY format.",
    'Bride religion': "Please choose the bride's religion:\n\n1. Hindu\n2. Muslim\n3. Christian\n4. Other",
    'Bride address': "Please provide the bride's address.",
    'Groom name': "Please tell me the groom's name.",
    'Groom DOB': "Please provide the groom's DOB in DD/MM/YYYY format.",
    'Groom religion': "Please choose the groom's religion:\n\n1. Hindu\n2. Muslim\n3. Christian\n4. Other",
    'Groom address': "Please provide the groom's address.",
    'Marriage date': 'Please provide the marriage date in DD/MM/YYYY format.',
    'Marriage place': 'Please provide the place of marriage.'
  };

  return map[field] || 'Please provide the missing information.';
}

// --------------------------------------------------
// Stage decisions
// --------------------------------------------------

const stage = currentStage;

// Details confirmed
if (stage === 'details_confirmation_pending' && message === '1') {
  result.customer_confirmed = true;
  result.correction_requested = false;
  result.proceed_confirmed = false;
  result.ready_to_create_lead = false;
  result.lead_creation_required = false;
  result.lead_payload_ready = false;

  if (serviceCategory === 'Hindu Marriage' && !selectedServiceOption) {
    result.current_stage = 'hindu_option_pending';
    result.hindu_option_required = true;
    result.hindu_option_selected = false;
    result.cost_shown = false;

    reply = replyByLanguage(
      language,
      'Please choose the required service option:\n\n1. Hindu Marriage Certificate\n2. Tamilnadu Marriage Certificate\n3. Both together\n\nPlease reply with 1, 2, or 3.',
      'தயவுசெய்து தேவையான சேவை விருப்பத்தை தேர்வு செய்யவும்:\n\n1. Hindu Marriage Certificate\n2. Tamilnadu Marriage Certificate\n3. Both together\n\nதயவுசெய்து 1, 2, அல்லது 3 என்று பதிலளிக்கவும்.',
      'Required service option choose pannunga:\n\n1. Hindu Marriage Certificate\n2. Tamilnadu Marriage Certificate\n3. Both together\n\n1, 2, or 3 nu reply pannunga.'
    );
  } else {
    result.current_stage = 'cost_confirmation_pending';
    result.cost_shown = true;

    reply = replyByLanguage(
      language,
      [
        'Thank you for confirming the details.',
        '',
        'Based on the information provided:',
        `Marriage Service: ${calculatedServiceName}`,
        `LANDOC Service Cost: ${calculatedServiceCost}`,
        '',
        'Would you like to proceed further?',
        'Reply 1 to Proceed.',
        'Reply 2 if you do not want to proceed.'
      ].join('\n'),
      [
        'விவரங்களை உறுதிப்படுத்தியதற்கு நன்றி.',
        '',
        'நீங்கள் பகிர்ந்த தகவல்களின் அடிப்படையில்:',
        `திருமண சேவை: ${calculatedServiceName}`,
        `LANDOC சேவை கட்டணம்: ${calculatedServiceCost}`,
        '',
        'மேலும் தொடர விரும்புகிறீர்களா?',
        'தொடர 1 என்று பதிலளிக்கவும்.',
        'தொடர விருப்பமில்லையெனில் 2 என்று பதிலளிக்கவும்.'
      ].join('\n'),
      [
        'Details confirm pannathukku thanks.',
        '',
        'Neenga kudutha information basis la:',
        `Marriage Service: ${calculatedServiceName}`,
        `LANDOC Service Cost: ${calculatedServiceCost}`,
        '',
        'Further proceed panna virumbureengala?',
        'Proceed panna 1 nu reply pannunga.',
        'Proceed panna viruppam illana 2 nu reply pannunga.'
      ].join('\n')
    );
  }
}

// Details correction
else if (stage === 'details_confirmation_pending' && message === '2') {
  result.current_stage = 'correction_pending';
  result.correction_requested = true;
  reply = replyByLanguage(
    language,
    'Which detail would you like to correct?',
    'எந்த விவரத்தை திருத்த வேண்டும்?',
    'Endha detail ah correct panna venum?'
  );
}

// Hindu option
else if (stage === 'hindu_option_pending') {
  if (['1', '2', '3'].includes(message)) {
    const optionMap = {
      '1': 'Hindu Marriage Certificate',
      '2': 'Tamilnadu Marriage Certificate',
      '3': 'Both together'
    };

    selectedServiceOption = optionMap[message];
    result.selected_service_option = selectedServiceOption;
    result.selected_service_option_backend = selectedServiceOption;
    result.selected_service_option_label = selectedServiceOption;
    result.hindu_option_selected = true;
    result.hindu_option_required = false;
    result.current_stage = 'cost_confirmation_pending';
    result.cost_shown = true;

    calculatedServiceName = `${selectedServiceOption} LANDOC Service`;
    result.calculated_service_name = calculatedServiceName;

    reply = [
      'Thank you for confirming the details.',
      '',
      'Based on the information provided:',
      `Marriage Service: ${calculatedServiceName}`,
      `Selected Option: ${selectedServiceOption}`,
      `LANDOC Service Cost: ${calculatedServiceCost}`,
      '',
      'Would you like to proceed further?',
      'Reply 1 to Proceed.',
      'Reply 2 if you do not want to proceed.'
    ].join('\n');
  } else {
    result.current_stage = 'hindu_option_pending';
    reply = 'Please reply only with 1, 2, or 3.';
  }
}

// Cost confirmation - proceed
else if (stage === 'cost_confirmation_pending' && message === '1') {
  const missing = getMissingMandatoryFields();

  if (missing.length > 0) {
    const firstMissing = missing[0];

    result.current_stage = stageForMissingField(firstMissing);
    result.ready_to_create_lead = false;
    result.lead_creation_required = false;
    result.lead_payload_ready = false;

    reply = [
      'Some required details are missing.',
      questionForMissingField(firstMissing)
    ].join('\n\n');
  } else {
    result.current_stage = 'lead_creation_pending';
    result.proceed_confirmed = true;
    result.not_interested = false;
    result.ready_to_create_lead = true;
    result.lead_creation_required = true;
    result.lead_payload_ready = true;
    result.cost_shown = true;

    reply = replyByLanguage(
      language,
      'Thank you. Please wait while we submit your details for team verification.',
      'நன்றி. உங்கள் விவரங்களை குழு சரிபார்ப்பிற்காக சமர்ப்பிக்கிறோம். தயவுசெய்து காத்திருக்கவும்.',
      'Thank you. Unga details team verification ku submit panrom. Konjam wait pannunga.'
    );
  }
}

// Cost confirmation - not proceed
else if (stage === 'cost_confirmation_pending' && message === '2') {
  result.current_stage = 'not_interested_reason_pending';
  result.not_interested = true;
  result.proceed_confirmed = false;
  result.ready_to_create_lead = false;
  result.lead_creation_required = false;
  result.lead_payload_ready = false;

  reply = replyByLanguage(
    language,
    'Could you please share the reason for not proceeding?',
    'தொடர விருப்பமில்லாத காரணத்தை பகிர முடியுமா?',
    'Proceed panna viruppam illadha reason ah share pannunga.'
  );
}

// Not interested reason
else if (stage === 'not_interested_reason_pending') {
  result.current_stage = 'lead_creation_pending';
  result.not_interested = true;
  result.not_interested_reason = message;
  result.ready_to_create_lead = true;
  result.lead_creation_required = true;
  result.lead_payload_ready = true;

  reply = replyByLanguage(
    language,
    'Thank you for sharing the reason. Please wait while we update this for our team review.',
    'காரணத்தை பகிர்ந்ததற்கு நன்றி. எங்கள் குழு பரிசீலனைக்காக இதை பதிவு செய்கிறோம். தயவுசெய்து காத்திருக்கவும்.',
    'Reason share pannathukku thanks. Team review ku update panrom. Konjam wait pannunga.'
  );
}

// Payment collection
else if (stage === 'payment_collection') {
  if (
    lowerMessage.includes('later') ||
    lowerMessage.includes('not now') ||
    lowerMessage.includes('cannot pay') ||
    lowerMessage.includes("can't pay") ||
    lowerMessage.includes('without payment')
  ) {
