    const v = safeString(value).toLowerCase();

    if (v === '1' || v.includes('hindu')) return 'Hindu';
    if (v === '2' || v.includes('muslim')) return 'Muslim';
    if (v === '3' || v.includes('christian')) return 'Christian';
    if (v === '4' || v.includes('other')) return 'Other';

    return '';
  }

  function parseDateDDMMYYYY(value) {
    const [dd, mm, yyyy] = safeString(value).split('/').map(Number);
    return new Date(yyyy, mm - 1, dd);
  }

  function calculateAge(dob) {
    if (!isValidDate(dob)) return '';
    const birthDate = parseDateDDMMYYYY(dob);
    const today = new Date();

    let age = today.getFullYear() - birthDate.getFullYear();
    const monthDiff = today.getMonth() - birthDate.getMonth();

    if (
      monthDiff < 0 ||
      (monthDiff === 0 && today.getDate() < birthDate.getDate())
    ) {
      age--;
    }

    return age;
  }

  function calculateMarriageDays(marriageDate) {
    if (!isValidDate(marriageDate)) return '';

    const marriage = parseDateDDMMYYYY(marriageDate);
    const today = new Date();

