function parseMaybeJson(value) {
  if (!value) return {};

  if (typeof value === 'object' && !Array.isArray(value)) {
    return value;
  }

  if (typeof value !== 'string') {
    return {};
  }

  try {
    return JSON.parse(value);
  } catch (e) {
    return {};
  }
}

function pick(...values) {
  for (const value of values) {
    if (value !== undefined && value !== null && String(value).trim() !== '') {
      return value;
    }
  }
  return '';
}

function parseDDMMYYYY(dateStr) {
  const value = String(dateStr || '').trim();

  if (!/^\d{2}\/\d{2}\/\d{4}$/.test(value)) {
    return null;
  }

  const [dd, mm, yyyy] = value.split('/').map(Number);
  const d = new Date(yyyy, mm - 1, dd);

  if (
    d.getFullYear() !== yyyy ||
    d.getMonth() !== mm - 1 ||
    d.getDate() !== dd
  ) {
    return null;
  }

  return d;
}

function calculateAge(dob) {
  const birthDate = parseDDMMYYYY(dob);

  if (!birthDate) {
    return null;
  }

  const today = new Date();
  let age = today.getFullYear() - birthDate.getFullYear();
  const monthDiff = today.getMonth() - birthDate.getMonth();

  if (
    monthDiff < 0 ||
    (monthDiff === 0 && today.getDate() < birthDate.getDate())
  ) {
    age--;
  }

  return age;
}

function calculateMarriageDays(marriageDate) {
  const date = parseDDMMYYYY(marriageDate);

  if (!date) {
    return null;
  }

  const today = new Date();
  return Math.floor(
    (today.getTime() - date.getTime()) / (1000 * 60 * 60 * 24)
  );
}

function normalizeReligion(value) {
  const v = String(value || '').trim().toLowerCase();

  if (v === '1' || v.includes('hindu')) return 'Hindu';
  if (v === '2' || v.includes('muslim') || v.includes('islam')) return 'Muslim';
  if (v === '3' || v.includes('christian')) return 'Christian';
  if (v === '4' || v.includes('other')) return 'Other';

  return String(value || '').trim();
}

function getMarriageServiceCategory(brideReligion, groomReligion) {
  const bride = normalizeReligion(brideReligion);
  const groom = normalizeReligion(groomReligion);

  if (bride === 'Hindu' && groom === 'Hindu') return 'Hindu Marriage';
  if (bride === 'Muslim' && groom === 'Muslim') return 'Muslim Marriage';
  if (bride === 'Christian' && groom === 'Christian') return 'Christian Marriage';

  if (bride && groom && bride !== groom) {
    return 'Special Marriage';
  }

  return 'Marriage Registration';
}

function serviceOptionCode(serviceCategory, selectedOptionLabel) {
  const category = String(serviceCategory || '').toLowerCase();
  const selected = String(selectedOptionLabel || '').toLowerCase();

  // Non-Hindu direct mapping required by Odoo service.type code
  if (category.includes('muslim')) return 'muslim_marriage';
  if (category.includes('christian')) return 'christian_marriage';
  if (category.includes('special')) return 'special_marriage';

  // Hindu option mapping
  if (selected.includes('hindu marriage certificate')) {
    return 'hindu_marriage_certificate';
  }

  if (selected.includes('tamilnadu marriage certificate')) {
    return 'tamilnadu_marriage_certificate';
  }

  if (selected.includes('both')) {
    return 'both_together';
  }

  if (category.includes('hindu')) {
    return 'hindu_marriage';
  }

  return '';
}

function toNumberFromRupee(value) {
  if (typeof value === 'number') return value;

  const cleaned = String(value || '').replace(/[^\d]/g, '');

  if (!cleaned) return null;

  return Number(cleaned);
}

