function parseSession(raw) {
  if (!raw) return {};
  if (typeof raw === 'object') return raw;

  try {
    return JSON.parse(raw);
  } catch (e) {
    return {};
  }
}

function toAmount(value) {
  if (value === null || value === undefined || value === '') return 0;
  return Number(String(value).replace(/[₹,\s]/g, '')) || 0;
}

function formatAmount(value) {
  const amount = toAmount(value);
  if (!amount) return '0';
  return String(amount);
}

function hasAttachment(input) {
  const attachmentInfo = String(input.attachment_info || '').trim();
  const binaryKey = String(input.attachment_binary_key || '').trim();
  const base64 = String(input.attachment_base64 || '').trim();

  return (
    input.has_attachment === true ||
    input.has_attachment === 'true' ||
    Number(input.attachment_count || 0) > 0 ||
    input.attachment_base64_available === true ||
    input.attachment_base64_available === 'true' ||
    base64 !== '' ||
    (attachmentInfo !== '' && attachmentInfo !== '||') ||
    (binaryKey !== '' && binaryKey !== 'undefined' && binaryKey !== 'null')
  );
}

function getPaymentAmounts(data) {
  const paidAmount = toAmount(
    data.paid_amount ||
    data.amount_paid ||
    data.payment_details?.amount_paid ||
    0
  );

  const totalAmount = toAmount(
    data.total_amount ||
    data.quotation_amount ||
    data.selected_service_cost ||
    data.calculated_service_cost ||
    data.service_details?.calculated_service_cost ||
    0
  );

  let pendingAmount = toAmount(
    data.payment_pending_amount ||
    data.payment_details?.payment_pending_amount ||
    0
  );

  if (pendingAmount <= 0 && totalAmount > 0) {
    pendingAmount = Math.max(totalAmount - paidAmount, 0);
  }

  return {
    paidAmount,
    totalAmount,
    pendingAmount
  };
}

