  'service_date_confirmed'
];

if (!paymentDocumentStages.includes(stage)) {
  return [
    {
      json: {
        ...input,
        payment_document_handled: false,
        need_document_checklist: false,
        need_document_upload_to_odoo: false,
        is_correction_upload: false,
        close_session: false
      }
    }
  ];
}

let nextStage = stage;
let reply = '';

/**
 * STAGE 1:
 * Payment completed by Odoo webhook OR customer selected pay later.
 * Now fetch document checklist.
 */
if (stage === 'fetch_document_checklist') {
  data.documents_status = 'ready_to_fetch_checklist';

  nextStage = 'fetch_document_checklist';

  const paymentSummary = data.payment_summary_message || '';

  reply = paymentSummary
    ? [
        paymentSummary,
        '',
        'Please wait while we fetch the required document checklist.'
      ].join('\n')
    : 'Please wait while we fetch the required document checklist.';

  return [
    {
      json: {
        ...input,
        output: reply,
        reply,
        last_reply: reply,
        active_service: 'marriage_registration',
        current_stage: nextStage,
        language,
        session_data: JSON.stringify(data),

        payment_document_handled: true,
        need_document_checklist: true,
        need_document_upload_to_odoo: false,
        is_correction_upload: false,

        close_session: false
      }
    }
  ];
}

/**
 * STAGE 2:
 * Waiting for Odoo/Razorpay payment confirmation.
 * Customer must reply 1 to check payment status.
 * If partial/full payment is available, move to document collection.
 * If payment is pending/failed, send payment link again.
 */
if (stage === 'waiting_for_payment_confirmation') {
  const checkPayment = lower === '1';

  const payLater =
    lower.includes('pay later') ||
    lower.includes('later') ||
    lower.includes('not now') ||
    lower.includes('will pay later') ||
    lower.includes('after document') ||
    lower.includes('after registration');

  const quotationLink =
    data.quotation_preview_url ||
    data.payment_link ||
    data.portal_payment_url ||
    '';

  const amounts = getPaymentAmounts(data);

  let paidAmount = amounts.paidAmount;
  let totalAmount = amounts.totalAmount;
  let pendingAmount = amounts.pendingAmount;

  if (pendingAmount <= 0 && totalAmount > 0) {
    pendingAmount = Math.max(totalAmount - paidAmount, 0);
  }

  data.paid_amount = paidAmount;
  data.total_amount = totalAmount;
  data.payment_pending_amount = pendingAmount;

  /**
   * Customer selected pay later.
   * This allows document collection, but balance must be collected before final delivery.
   */
  if (payLater) {
    data.payment_status = 'pending';
    data.payment_stage = 'pay_later';

    if (!data.payment_pending_amount) {
      data.payment_pending_amount =
        data.total_amount ||
        data.quotation_amount ||
        data.selected_service_cost ||
        data.calculated_service_cost ||
        '';
    }

    data.can_collect_documents = true;
    data.can_deliver_final_documents = false;
    data.documents_status = 'ready_to_fetch_checklist';

    nextStage = 'fetch_document_checklist';

    reply = [
      'Okay, we will continue with document collection.',
      '',
      `Total amount: ₹${formatAmount(data.total_amount || data.quotation_amount || data.selected_service_cost || data.calculated_service_cost)}`,
      `Paid amount: ₹${formatAmount(data.paid_amount || 0)}`,
      `Remaining amount: ₹${formatAmount(data.payment_pending_amount || data.total_amount || data.quotation_amount || data.selected_service_cost || data.calculated_service_cost)}`,
      '',
      'Payment can be completed later, but the pending balance must be paid before final document delivery.'
    ].join('\n');

    data.payment_summary_message = reply;

  /**
   * Customer did not press 1.
   * Tell customer to press 1 to check payment status.
   */
  } else if (!checkPayment) {
    nextStage = 'waiting_for_payment_confirmation';

    reply = [
      'Please complete the payment using the quotation link below:',
      '',
      quotationLink || 'Payment link is not available. Our team will share the payment link shortly.',
      '',
      'After payment, reply 1 to check your payment status.'
    ].join('\n');

    data.payment_summary_message = reply;

  /**
   * Customer pressed 1.
   * Check payment status using actual amount and stored status.
   */
  } else {
    const paymentStatus = String(data.payment_status || '').toLowerCase();

    const isFullPayment =
      paidAmount >= totalAmount &&
      totalAmount > 0;

    const isPartialPayment =
      paidAmount > 0 &&
      pendingAmount > 0;

    const isPaymentSuccess =
      isFullPayment ||
      isPartialPayment ||
      paymentStatus === 'fully_paid' ||
      paymentStatus === 'paid' ||
      paymentStatus === 'partial_paid' ||
      data.can_collect_documents === true;

    if (isPaymentSuccess) {
      data.can_collect_documents = true;
      data.documents_status = 'ready_to_fetch_checklist';

      nextStage = 'fetch_document_checklist';

      if (isFullPayment || paymentStatus === 'fully_paid' || paymentStatus === 'paid' || pendingAmount <= 0) {
        data.payment_status = 'fully_paid';
        data.can_deliver_final_documents = true;
        data.payment_pending_amount = 0;

        reply = [
          'Payment confirmed successfully. Thank you.',
          '',
          `Total amount: ₹${formatAmount(totalAmount)}`,
          `Paid amount: ₹${formatAmount(paidAmount)}`,
          'Remaining amount: ₹0',
          '',
          'We will now continue with document collection.'
        ].join('\n');

      } else {
        data.payment_status = 'partial_paid';
        data.can_deliver_final_documents = false;

        reply = [
          'Partial payment received successfully. Thank you.',
          '',
          `Total amount: ₹${formatAmount(totalAmount)}`,
          `Paid amount: ₹${formatAmount(paidAmount)}`,
          `Remaining amount: ₹${formatAmount(pendingAmount)}`,
          '',
          'We will now continue with document collection.',
          '',
          'Note: The remaining amount must be paid before final document delivery.'
        ].join('\n');
      }

      data.payment_summary_message = reply;

    } else {
      data.payment_status = data.payment_status || 'pending';
      data.can_collect_documents = false;
      data.can_deliver_final_documents = false;
      data.documents_status = 'payment_pending';

      nextStage = 'waiting_for_payment_confirmation';

      reply = [
        'Payment is still pending or not confirmed.',
        '',
        `Total amount: ₹${formatAmount(data.total_amount || data.quotation_amount || data.selected_service_cost || data.calculated_service_cost)}`,
        `Paid amount: ₹${formatAmount(data.paid_amount || 0)}`,
        `Remaining amount: ₹${formatAmount(data.payment_pending_amount || data.total_amount || data.quotation_amount || data.selected_service_cost || data.calculated_service_cost)}`,
        '',
        'Please complete the payment using the quotation link below:',
        '',
        quotationLink || 'Payment link is not available. Our team will share the payment link shortly.',
        '',
        'After payment, reply 1 to check your payment status.'
      ].join('\n');

      data.payment_summary_message = reply;
    }
  }

  return [
    {
      json: {
        ...input,
        output: reply,
        reply,
        last_reply: reply,
        active_service: 'marriage_registration',
        current_stage: nextStage,
        language,
        session_data: JSON.stringify(data),

        payment_document_handled: true,
        need_document_checklist: nextStage === 'fetch_document_checklist',
        need_document_upload_to_odoo: false,
        is_correction_upload: false,

        close_session: false
      }
    }
  ];
}

/**
 * STAGE 3:
 * Document correction collection.
 * Customer should reply 1 to view correction document,
 * then upload corrected document.
 */
if (stage === 'document_correction_collection') {
  const attachmentReceived = hasAttachment(input);

  const viewCorrection = lower === '1';

  let correctionQueue = Array.isArray(data.correction_queue)
    ? data.correction_queue
    : [];

  /**
   * If correction_queue is missing, rebuild from required_documents.
   */
  if (!correctionQueue.length && Array.isArray(data.required_documents)) {
    correctionQueue = data.required_documents
      .map((doc, index) => ({ ...doc, index }))
      .filter((doc) =>
        doc.status === 'correction_required' ||
        doc.correction_required === true ||
        doc.correction_required === 'true'
      );

    data.correction_queue = correctionQueue;
  }

  const currentCorrection = correctionQueue[0];

  /**
   * If no correction is pending, move back to verification stage.
   */
  if (!currentCorrection) {
    data.document_correction_required = false;
    data.documents_status = 'pending_verification';

    reply = [
      'There are no pending correction documents.',
      '',
      'Your documents are under verification.',
      '',
      'If you want to know your document verification status, reply 1.'
    ].join('\n');

    return [
      {
        json: {
          ...input,
          output: reply,
          reply,
          last_reply: reply,
          active_service: 'marriage_registration',
          current_stage: 'documents_pending_verification',
          language,
          session_data: JSON.stringify(data),

          payment_document_handled: true,
          need_document_checklist: false,
          need_document_upload_to_odoo: false,
          is_correction_upload: false,

          close_session: false
        }
      }
    ];
  }

  const correctionCode =
    currentCorrection.code ||
    currentCorrection.description_code ||
    data.current_document_code ||
    '';

  const correctionName =
    currentCorrection.name ||
    data.current_document_name ||
    'Required correction document';

  const correctionReason =
    currentCorrection.correction_reason ||
    currentCorrection.reason ||
    'Please upload the correct document.';

  data.current_document_index = Number(currentCorrection.index || 0);
  data.current_document_code = correctionCode;
  data.current_document_name = correctionName;
  data.documents_status = attachmentReceived
    ? 'uploading_correction_document'
    : 'correction_required';
  data.document_correction_required = true;

  /**
   * Customer has not pressed 1 and has not uploaded file.
   * Show only instruction.
   */
  if (!attachmentReceived && !viewCorrection) {
    reply = [
      'Document correction is required.',
      '',
      `Correction documents pending: ${correctionQueue.length}`,
      '',
      'Reply 1 to view the required correction document.'
    ].join('\n');

    return [
      {
        json: {
          ...input,
          output: reply,
          reply,
          last_reply: reply,
          active_service: 'marriage_registration',
          current_stage: 'document_correction_collection',
          language,
          session_data: JSON.stringify(data),

          payment_document_handled: true,
          need_document_checklist: false,
          need_document_upload_to_odoo: false,
          is_correction_upload: false,

          current_document_index: data.current_document_index,
          current_document_code: correctionCode,
          current_document_name: correctionName,

          close_session: false
        }
      }
    ];
  }

  /**
   * Customer pressed 1.
   * Show correction document and reason.
   */
  if (!attachmentReceived && viewCorrection) {
    reply = [
      'Document correction required.',
      '',
      `Document: ${correctionName}`,
      '',
      `Reason: ${correctionReason}`,
      '',
      'Please upload the corrected document here.'
    ].join('\n');

    return [
      {
        json: {
          ...input,
          output: reply,
          reply,
          last_reply: reply,
          active_service: 'marriage_registration',
          current_stage: 'document_correction_collection',
          language,
          session_data: JSON.stringify(data),

          payment_document_handled: true,
          need_document_checklist: false,
          need_document_upload_to_odoo: false,
          is_correction_upload: false,

          current_document_index: data.current_document_index,
          current_document_code: correctionCode,
          current_document_name: correctionName,

          close_session: false
        }
      }
    ];
  }

  /**
   * Customer uploaded corrected document.
   * Send to same Odoo upload branch.
   */
  reply = `Uploading corrected document: ${correctionName}`;

  return [
    {
      json: {
        ...input,
        output: reply,
        reply,
        last_reply: reply,
        active_service: 'marriage_registration',
        current_stage: 'document_correction_collection',
        language,
        session_data: JSON.stringify(data),

        payment_document_handled: true,
        need_document_checklist: false,
        need_document_upload_to_odoo: true,
        is_correction_upload: true,

        current_document_index: data.current_document_index,
        current_document_code: correctionCode,
        current_document_name: correctionName,

        close_session: false
      }
    }
  ];
}

/**
 * STAGE 4:
 * Customer is uploading checklist documents one by one.
 */
if (stage === 'documents_collection') {
  const attachmentReceived = hasAttachment(input);
  const docs = Array.isArray(data.required_documents) ? data.required_documents : [];
  const index = Number(data.current_document_index || 0);
  const currentDoc = docs[index];

  /**
   * If checklist is missing, go fetch checklist again.
   */
  if (!docs.length) {
    data.documents_status = 'ready_to_fetch_checklist';

    nextStage = 'fetch_document_checklist';

    reply = 'Please wait while we fetch the required document checklist.';

    return [
      {
        json: {
          ...input,
          output: reply,
