          language,
          session_data: JSON.stringify(data),

          payment_document_handled: true,
          need_document_checklist: true,
          need_document_upload_to_odoo: false,
          is_correction_upload: false,

          close_session: false
        }
      }
    ];
  }

  /**
   * If all documents are completed.
   */
  if (!currentDoc) {
    data.documents_status = 'pending_verification';
    data.documents_collected = true;
    data.current_document_index = docs.length;
    data.current_document_code = '';
    data.current_document_name = '';

    nextStage = 'documents_pending_verification';

    const amounts = getPaymentAmounts(data);

    data.paid_amount = amounts.paidAmount;
    data.total_amount = amounts.totalAmount;
    data.payment_pending_amount = amounts.pendingAmount;

    if (amounts.pendingAmount > 0) {
      reply = [
        'Thank you. We have received the required documents.',
        '',
        'Our team will verify and update you if anything else is required.',
        '',
        `Balance payment pending: ₹${formatAmount(amounts.pendingAmount)}.`,
        '',
        'This balance must be paid before final document delivery.'
      ].join('\n');
    } else {
      reply = 'Thank you. We have received the required documents. Our team will verify and update you if anything else is required.';
    }

    return [
      {
        json: {
          ...input,
          output: reply,
          reply,
          last_reply: reply,
          active_service: 'marriage_registration',
          current_stage: nextStage,
          language,
          session_data: JSON.stringify(data),

          payment_document_handled: true,
          need_document_checklist: false,
          need_document_upload_to_odoo: false,
          is_correction_upload: false,

          close_session: false
        }
      }
    ];
  }

  /**
   * If customer did not upload file, ask for the current document again.
   */
  if (!attachmentReceived) {
    nextStage = 'documents_collection';

    reply = `Please upload: ${currentDoc.name}`;

    return [
      {
        json: {
          ...input,
          output: reply,
          reply,
          last_reply: reply,
          active_service: 'marriage_registration',
          current_stage: nextStage,
          language,
          session_data: JSON.stringify(data),

          payment_document_handled: true,
          need_document_checklist: false,
          need_document_upload_to_odoo: false,
          is_correction_upload: false,

          current_document_index: index,
          current_document_code: currentDoc.code || currentDoc.description_code || '',
          current_document_name: currentDoc.name || '',

          close_session: false
        }
      }
    ];
  }

  /**
   * Customer uploaded current document.
   * Send to Odoo upload branch.
   */
  data.documents_status = 'uploading_current_document';
  data.current_document_index = index;
  data.current_document_code = currentDoc.code || currentDoc.description_code || '';
  data.current_document_name = currentDoc.name || '';

  nextStage = 'documents_collection';

  reply = `Uploading: ${currentDoc.name}`;

  return [
    {
      json: {
        ...input,
        output: reply,
        reply,
        last_reply: reply,
        active_service: 'marriage_registration',
        current_stage: nextStage,
        language,
        session_data: JSON.stringify(data),

        payment_document_handled: true,
        need_document_checklist: false,
        need_document_upload_to_odoo: true,
        is_correction_upload: false,

        current_document_index: index,
        current_document_code: currentDoc.code || currentDoc.description_code || '',
        current_document_name: currentDoc.name || '',

        close_session: false
      }
    }
  ];
}

/**
 * STAGE 5:
 * Documents uploaded and pending backend verification.
 * Customer can reply 1 to check document verification status.
 */
if (stage === 'documents_pending_verification') {
  const checkDocumentStatus =
    lower === '1' ||
    lower.includes('status') ||
    lower.includes('document status') ||
    lower.includes('verification');

  let correctionQueue = Array.isArray(data.correction_queue)
    ? data.correction_queue
    : [];

  /**
   * If correction queue is missing, rebuild it from required_documents.
   */
  if (!correctionQueue.length && Array.isArray(data.required_documents)) {
    correctionQueue = data.required_documents
      .map((doc, index) => ({ ...doc, index }))
      .filter((doc) =>
        doc.status === 'correction_required' ||
        doc.correction_required === true ||
        doc.correction_required === 'true'
      );

    data.correction_queue = correctionQueue;
  }

  const hasCorrection =
    correctionQueue.length > 0 ||
    data.document_correction_required === true ||
    data.document_correction_required === 'true' ||
    data.documents_status === 'correction_required';

  const documentsVerified =
    data.documents_verified === true ||
    data.documents_verified === 'true' ||
    data.documents_status === 'verified' ||
    data.document_verification_status === 'verified';

  /**
   * Customer did not press 1.
   * Just remind them how to check document status.
   */
  if (!checkDocumentStatus) {
    reply = [
      'Your documents are under verification.',
      '',
      'Our backend team will contact you if any correction is required.',
      '',
      'If you want to know your document verification status, reply 1.'
    ].join('\n');

    return [
      {
        json: {
          ...input,
          output: reply,
          reply,
          last_reply: reply,
          active_service: 'marriage_registration',
          current_stage: 'documents_pending_verification',
          language,
          session_data: JSON.stringify(data),

          payment_document_handled: true,
          need_document_checklist: false,
          need_document_upload_to_odoo: false,
          is_correction_upload: false,

          close_session: false
        }
      }
    ];
  }

  /**
   * Customer pressed 1 and correction is available.
   */
  if (hasCorrection) {
    const currentCorrection = correctionQueue[0];

    if (currentCorrection) {
      data.current_document_index = Number(currentCorrection.index || 0);
      data.current_document_code = currentCorrection.code || currentCorrection.description_code || '';
      data.current_document_name = currentCorrection.name || '';
      data.documents_status = 'correction_required';
      data.document_correction_required = true;

      reply = [
        'Document correction required.',
        '',
        `Document: ${data.current_document_name}`,
        '',
        `Reason: ${currentCorrection.correction_reason || currentCorrection.reason || 'Please upload the correct document.'}`,
        '',
        'Please upload the corrected document here.'
      ].join('\n');

      return [
        {
          json: {
            ...input,
            output: reply,
            reply,
            last_reply: reply,
            active_service: 'marriage_registration',
            current_stage: 'document_correction_collection',
