            session_data: JSON.stringify(data),

            payment_document_handled: true,
            need_document_checklist: false,
            need_document_upload_to_odoo: false,
            is_correction_upload: false,

            current_document_index: data.current_document_index,
            current_document_code: data.current_document_code,
            current_document_name: data.current_document_name,

            close_session: false
          }
        }
      ];
    }
  }

  /**
   * Customer pressed 1 and all documents are verified.
   */
  if (documentsVerified) {
  data.service_date_status = 'ready_to_fetch_dates';
  data.need_service_date = true;

  reply = [
    'Your documents have been verified successfully.',
    '',
    'Now we can proceed with registration date selection.',
    '',
    'Please reply 1 to view available registration dates.'
  ].join('\n');

  return [
    {
      json: {
        ...input,
        output: reply,
        reply,
        last_reply: reply,
        active_service: 'marriage_registration',
        current_stage: 'service_date_fetch',
        language,
        session_data: JSON.stringify(data),

        payment_document_handled: true,
        need_document_checklist: false,
        need_document_upload_to_odoo: false,
        is_correction_upload: false,

        need_service_date_fetch: false,
        need_service_date_save: false,

        close_session: false
      }
    }
  ];
}

  /**
   * Customer pressed 1 but no correction and not verified yet.
   */
  reply = [
    'Your documents are still under verification.',
    '',
    'Our backend team will contact you if any correction is required.',
    '',
    'Please check again later by replying 1.'
  ].join('\n');

  return [
    {
      json: {
        ...input,
        output: reply,
        reply,
        last_reply: reply,
        active_service: 'marriage_registration',
        current_stage: 'documents_pending_verification',
        language,
        session_data: JSON.stringify(data),

        payment_document_handled: true,
        need_document_checklist: false,
        need_document_upload_to_odoo: false,
        is_correction_upload: false,

        close_session: false
      }
    }
  ];
}


