      'Available registration dates:',
      '',
      ...dateLines,
      '',
      'Reply with the option number to select your registration date.'
    ].join('\n');

    return [
      {
        json: {
          ...input,
          output: reply,
          reply,
          last_reply: reply,
          active_service: 'marriage_registration',
          current_stage: 'service_date_selection',
          language,
          session_data: JSON.stringify(data),

          payment_document_handled: true,
          need_document_checklist: false,
          need_document_upload_to_odoo: false,
          is_correction_upload: false,

          need_service_date_fetch: false,
          need_service_date_save: false,

          close_session: false
        }
      }
    ];
  }

  const selectedDate = availableDates[selectedOption - 1];

  data.selected_service_date_option = selectedOption;
  data.selected_service_date = selectedDate.date || selectedDate.available_date || '';
  data.selected_service_date_display = selectedDate.display_date || selectedDate.date || selectedDate.available_date || '';
  data.selected_service_date_location = selectedDate.location || '';
  data.service_date_status = 'saving_selected_date';

  reply = 'Please wait while we save your selected registration date.';

  return [
    {
      json: {
        ...input,
        output: reply,
        reply,
        last_reply: reply,
        active_service: 'marriage_registration',
        current_stage: 'service_date_selection',
        language,
        session_data: JSON.stringify(data),

        payment_document_handled: true,
        need_document_checklist: false,
        need_document_upload_to_odoo: false,
        is_correction_upload: false,

        need_service_date_fetch: false,
        need_service_date_save: true,

        selected_service_date_option: selectedOption,
        selected_service_date: data.selected_service_date,
        selected_service_date_display: data.selected_service_date_display,
        selected_service_date_location: data.selected_service_date_location,

        close_session: false
      }
    }
  ];
}

/**
 * Final fallback:
 * Should rarely reach here.
 */
return [
  {
    json: {
      ...input,
      payment_document_handled: false,
      need_document_checklist: false,
      need_document_upload_to_odoo: false,
      is_correction_upload: false,
      close_session: false
    }
  }
];

const input = $input.first().json || {};
const body = input.body || {};

const paidAmount = Number(body.paid_amount || 0);
const totalAmount = Number(body.total_amount || 0);
const pendingAmount = Math.max(totalAmount - paidAmount, 0);

let paymentStatus = 'pending';

if (paidAmount >= totalAmount && totalAmount > 0) {
  paymentStatus = 'fully_paid';
} else if (paidAmount > 0 && paidAmount < totalAmount) {
  paymentStatus = 'partial_paid';
} else {
  paymentStatus = 'pending';
}

return [
  {
    json: {
      event: body.event || '',
      lead_id: body.lead_id || '',
      request_number: body.request_number || '',
      payment_status_from_odoo: body.payment_status || '',
      payment_status: paymentStatus,
      paid_amount: paidAmount,
      total_amount: totalAmount,
      payment_pending_amount: pendingAmount,
      can_collect_documents: paymentStatus === 'fully_paid' || paymentStatus === 'partial_paid',
      can_deliver_final_documents: pendingAmount === 0,

      customer_id: body.bot_customer_id || body.bot_session_id || '',
      bot_customer_id: body.bot_customer_id || '',
      channel: body.bot_channel || 'chat',

      current_stage:
        paymentStatus === 'fully_paid' || paymentStatus === 'partial_paid'
          ? 'fetch_document_checklist'
          : 'waiting_for_payment_confirmation',

      received_at: new Date().toISOString()
    }
  }
];

const payment = $('CODE_Normalize_Payment_Status').item.json;
const row = $input.first().json || {};

function parseSession(raw) {
  if (!raw) return {};
  if (typeof raw === 'object') return raw;

  try {
    return JSON.parse(raw);
  } catch (e) {
    return {};
  }
}

function toAmount(value) {
  if (value === null || value === undefined || value === '') return 0;
  return Number(String(value).replace(/[₹,\s]/g, '')) || 0;
}

function formatAmount(value) {
  const amount = toAmount(value);
  return String(amount);
}

const data = parseSession(row.session_data);

const previousStage =
  row.current_stage ||
  data.current_stage ||
  'waiting_for_payment_confirmation';

/**
 * Do not overwrite these stages if payment webhook comes again later.
 */
const documentStages = [
  'documents_collection',
  'documents_pending_verification',
  'document_correction_collection'
];

const isAlreadyInDocumentFlow = documentStages.includes(previousStage);

/**
 * Payment values from Odoo webhook.
 */
data.payment_status_from_odoo = payment.payment_status_from_odoo || '';
data.payment_status = payment.payment_status || 'pending';
data.payment_stage = payment.payment_status || 'pending';

data.paid_amount = toAmount(payment.paid_amount || 0);

data.total_amount = toAmount(
  payment.total_amount ||
  data.total_amount ||
  data.quotation_amount ||
  data.selected_service_cost ||
  data.calculated_service_cost ||
  0
);

data.payment_pending_amount = toAmount(
  payment.payment_pending_amount ||
  Math.max(data.total_amount - data.paid_amount, 0)
);

data.payment_reference = payment.payment_reference || data.payment_reference || '';

data.can_collect_documents = payment.can_collect_documents === true;
data.can_deliver_final_documents = payment.can_deliver_final_documents === true;

data.payment_event = payment.event || 'payment_confirmed';
data.payment_confirmed_at = payment.received_at || new Date().toISOString();

data.odoo_lead_id = payment.lead_id || data.odoo_lead_id || '';
data.odoo_request_number = payment.request_number || data.odoo_request_number || '';

data.quotation_id = payment.quotation_id || data.quotation_id || '';
data.quotation_number = payment.quotation_number || data.quotation_number || '';
data.invoice_id = payment.invoice_id || data.invoice_id || '';
data.invoice_number = payment.invoice_number || data.invoice_number || '';

const quotationLink =
  data.quotation_preview_url ||
  data.payment_link ||
  data.portal_payment_url ||
  '';

let reply = '';

/**
 * CASE 1:
 * Full payment received.
 */
if (data.payment_status === 'fully_paid' || data.payment_status === 'paid') {
  data.can_collect_documents = true;
  data.can_deliver_final_documents = true;

  if (!isAlreadyInDocumentFlow) {
    data.documents_status = 'payment_confirmed_waiting_customer_check';
  }

  reply = [
    'Payment confirmed successfully. Thank you.',
    '',
    `Total amount: ₹${formatAmount(data.total_amount)}`,
    `Paid amount: ₹${formatAmount(data.paid_amount)}`,
    'Remaining amount: ₹0',
    '',
    isAlreadyInDocumentFlow
      ? 'Your document process will continue from the current stage.'
      : 'Reply 1 to continue to document collection.'
  ].join('\n');

/**
 * CASE 2:
 * Partial payment received.
 */
} else if (data.payment_status === 'partial_paid') {
  data.can_collect_documents = true;
  data.can_deliver_final_documents = false;

  if (!isAlreadyInDocumentFlow) {
    data.documents_status = 'payment_confirmed_waiting_customer_check';
  }

  reply = [
    'Partial payment received successfully. Thank you.',
    '',
    `Total amount: ₹${formatAmount(data.total_amount)}`,
    `Paid amount: ₹${formatAmount(data.paid_amount)}`,
    `Remaining amount: ₹${formatAmount(data.payment_pending_amount)}`,
    '',
    'Note: The remaining amount must be paid before final document delivery.',
    '',
    isAlreadyInDocumentFlow
      ? 'Your document process will continue from the current stage.'
      : 'Reply 1 to continue to document collection.'
  ].join('\n');

/**
 * CASE 3:
 * Payment pending / failed / not confirmed.
 */
} else {
  data.documents_status = 'payment_pending';
  data.can_collect_documents = false;
  data.can_deliver_final_documents = false;

  reply = [
    'Payment is still pending or payment was not successful.',
    '',
    `Total amount: ₹${formatAmount(data.total_amount || data.quotation_amount || 0)}`,
    `Paid amount: ₹${formatAmount(data.paid_amount || 0)}`,
    `Remaining amount: ₹${formatAmount(data.payment_pending_amount || data.total_amount || data.quotation_amount || 0)}`,
    '',
    'Please complete the payment using the quotation link below:',
    '',
    quotationLink || 'Payment link is not available. Our team will share the payment link shortly.',
    '',
    'After payment, reply 1 to check your payment status.'
  ].join('\n');
}

data.payment_summary_message = reply;

/**
 * IMPORTANT:
 * Payment webhook should not directly start document collection anymore.
 * Customer must reply 1 in chatbot.
 */
let nextStage = previousStage;

if (!isAlreadyInDocumentFlow) {
  nextStage = 'waiting_for_payment_confirmation';
}

return [
  {
    json: {
      id: row.id,
      customer_id: row.customer_id || payment.customer_id,
      channel: row.channel || payment.channel || 'chat',
      active_service: row.active_service || 'marriage_registration',
      current_stage: nextStage,
      language: row.language || 'English',
      session_data: JSON.stringify(data),
      updated_at: new Date().toISOString(),
      last_reply: reply
    }
  }
];

