parameters.jsCode:
const input = $input.first().json || {};

const success = input.success === true || input.success === 'true';
const response = input.response || {};

function parseSession(raw) {
  if (!raw) return {};
  if (typeof raw === 'object') return raw;
  try {
    return JSON.parse(raw);
  } catch (e) {
    return {};
  }
}

function toAmount(value) {
  if (value === null || value === undefined || value === '') return 0;
  return Number(String(value).replace(/[₹,\s]/g, '')) || 0;
}

const data = parseSession(input.session_data);

const isCorrectionUpload =
  input.is_correction_upload === true ||
  input.is_correction_upload === 'true' ||
  data.documents_status === 'uploading_correction_document';

const docs = Array.isArray(data.required_documents) ? data.required_documents : [];

const currentIndex = Number(
  input.current_document_index !== undefined
    ? input.current_document_index
    : data.current_document_index || 0
);

const currentDoc = docs[currentIndex];

if (!success) {
  const reply = isCorrectionUpload
    ? 'Corrected document upload failed. Please try uploading the same corrected document again.'
    : 'Document upload failed. Please try uploading the same document again.';

  return [
    {
      json: {
        ...input,
        output: reply,
        reply,
        last_reply: reply,
        active_service: 'marriage_registration',
        current_stage: isCorrectionUpload ? 'document_correction_collection' : 'documents_collection',
        language: input.language || 'English',
        session_data: JSON.stringify(data),
        customer_id: input.customer_id,
        channel: input.channel || 'chat',
        close_session: false
      }
    }
  ];
}

/**
 * CASE 1:
 * Correction document upload success.
 */
if (isCorrectionUpload) {
  const uploadedCode =
    input.current_document_code ||
    data.current_document_code ||
    response.description_code ||
    '';

  const uploadedName =
    input.current_document_name ||
    data.current_document_name ||
    currentDoc?.name ||
    'Corrected document';

  data.required_documents = docs.map((doc) => {
    const docCode = doc.code || doc.description_code || '';

    if (docCode === uploadedCode) {
      return {
        ...doc,
        status: 'correction_uploaded',
        correction_required: false,
        correction_uploaded_at: new Date().toISOString(),
        attachment_info: input.attachment_info || doc.attachment_info || '',
        uploaded_at: new Date().toISOString()
      };
    }

    return doc;
  });

  const correctionQueue = Array.isArray(data.correction_queue)
    ? data.correction_queue
    : [];

  const remainingQueue = correctionQueue.filter((item) => {
    const itemCode = item.code || item.description_code || '';
    return itemCode !== uploadedCode;
  });

  data.correction_queue = remainingQueue;

  const nextCorrection = remainingQueue[0];

  let reply = '';

  /**
   * More correction documents pending.
   */
  if (nextCorrection) {
    data.current_document_index = Number(nextCorrection.index || 0);
    data.current_document_code = nextCorrection.code || nextCorrection.description_code || '';
    data.current_document_name = nextCorrection.name || '';
    data.documents_status = 'correction_required';
    data.document_correction_required = true;
    data.documents_collected = false;

    reply = [
      `Received corrected document: ${uploadedName}.`,
      '',
      `Please upload the corrected document: ${nextCorrection.name}`,
      '',
      `Reason: ${nextCorrection.correction_reason || nextCorrection.reason || 'Please upload the correct document.'}`
    ].join('\n');

    return [
      {
        json: {
          ...input,
          output: reply,
          reply,
          last_reply: reply,
          active_service: 'marriage_registration',
          current_stage: 'document_correction_collection',
          language: input.language || 'English',
          session_data: JSON.stringify(data),
          customer_id: input.customer_id,
          channel: input.channel || 'chat',
          close_session: false
        }
      }
    ];
  }

  /**
   * All correction documents uploaded.
   */
  data.current_document_index = data.required_documents.length;
  data.current_document_code = '';
  data.current_document_name = '';
  data.documents_status = 'pending_verification';
  data.document_correction_required = false;
  data.documents_collected = true;
  data.documents_verified = false;
  data.document_verification_status = 'pending_verification';

  reply = [
    `Received corrected document: ${uploadedName}.`,
    '',
    'Thank you. We have received all requested correction documents.',
    '',
    'Our backend team will verify the corrected documents and contact you if anything else is required.',
    '',
    'If you want to know your document verification status, reply 1.'
  ].join('\n');

  return [
    {
      json: {
        ...input,
        output: reply,
        reply,
        last_reply: reply,
        active_service: 'marriage_registration',
        current_stage: 'documents_pending_verification',
        language: input.language || 'English',
        session_data: JSON.stringify(data),
        customer_id: input.customer_id,
        channel: input.channel || 'chat',
        close_session: false
      }
    }
  ];
}

/**
 * CASE 2:
 * Normal document upload success.
 */
if (currentDoc) {
  docs[currentIndex] = {
    ...currentDoc,
    status: 'uploaded',
    attachment_info: input.attachment_info || '',
    uploaded_at: new Date().toISOString()
  };
}

const nextIndex = currentIndex + 1;
const nextDoc = docs[nextIndex];

data.required_documents = docs;
data.current_document_index = nextIndex;

let reply = '';

/**
 * More normal documents pending.
 */
if (nextDoc) {
  data.current_document_code = nextDoc.code || nextDoc.description_code || '';
  data.current_document_name = nextDoc.name || '';
  data.documents_status = 'collecting';
  data.documents_collected = false;

  reply = [
    `Received: ${currentDoc?.name || 'Document'}.`,
    '',
    `Please upload: ${nextDoc.name}`
  ].join('\n');

/**
 * All normal documents uploaded.
 */
} else {
  data.current_document_code = '';
  data.current_document_name = '';
  data.documents_status = 'pending_verification';
  data.document_verification_status = 'pending_verification';
  data.documents_verified = false;
  data.documents_collected = true;
  data.document_correction_required = false;

  const paidAmount = toAmount(
    data.paid_amount ||
    data.amount_paid ||
    data.payment_details?.amount_paid ||
    0
  );

  const totalAmount = toAmount(
    data.total_amount ||
    data.quotation_amount ||
    data.selected_service_cost ||
    data.calculated_service_cost ||
    data.service_details?.calculated_service_cost ||
    0
  );

  let pendingAmount = toAmount(
    data.payment_pending_amount ||
    data.payment_details?.payment_pending_amount ||
    0
  );

  if (pendingAmount <= 0 && totalAmount > 0) {
    pendingAmount = Math.max(totalAmount - paidAmount, 0);
  }

  data.payment_pending_amount = pendingAmount;

  if (pendingAmount > 0) {
    reply = [
      'Thank you. We have received all required documents.',
      '',
      'Our backend team will verify the documents and contact you if any correction is required.',
      '',
      `Balance payment pending: ₹${pendingAmount}.`,
      '',
      'This balance must be paid before final document delivery.',
      '',
      'If you want to know your document verification status, reply 1.'
    ].join('\n');
  } else {
    reply = [
      'Thank you. We have received all required documents.',
      '',
      'Our backend team will verify the documents and contact you if any correction is required.',
      '',
      'If you want to know your document verification status, reply 1.'
    ].join('\n');
  }
}

return [
  {
    json: {
      ...input,
      output: reply,
      reply,
      last_reply: reply,
      active_service: 'marriage_registration',
      current_stage: nextDoc ? 'documents_collection' : 'documents_pending_verification',
      language: input.language || 'English',
      session_data: JSON.stringify(data),
      customer_id: input.customer_id,
      channel: input.channel || 'chat',
      close_session: false
    }
  }
];

const input = $input.first().json || {};

function parseSession(raw) {
  if (!raw) return {};
  if (typeof raw === 'object') return raw;
  try {
    return JSON.parse(raw);
  } catch (e) {
    return {};
  }
}

const data = parseSession(input.session_data);

const isCorrectionUpload =
  input.is_correction_upload === true ||
  input.is_correction_upload === 'true' ||
  data.documents_status === 'uploading_correction_document';

if (input.need_document_upload_to_odoo !== true) {
  return [
    {
      json: {
        ...input,
        output: input.output || input.reply || 'Please continue.',
        reply: input.reply || input.output || 'Please continue.',
        need_document_upload_to_odoo: false,
        skipped_upload_prepare: true,
        is_correction_upload: isCorrectionUpload
      }
    }
  ];
}

let base64Data = input.attachment_base64 || '';
let filename = input.attachment_file_name || 'uploaded_document';
let mimetype = input.attachment_mime_type || 'application/octet-stream';

const binaryKey = input.attachment_binary_key || 'data0';

if (!base64Data) {
  if ($binary && $binary[binaryKey]) {
    const buffer = await this.helpers.getBinaryDataBuffer(0, binaryKey);
    base64Data = buffer.toString('base64');

    filename = $binary[binaryKey].fileName || filename;
    mimetype = $binary[binaryKey].mimeType || mimetype;
  }
}

if (!base64Data) {
  throw new Error(
    `No attachment base64 or binary file found. binaryKey=${binaryKey}, file=${filename}`
  );
}

const serviceCategory = String(
  data.service_details?.service_category ||
  data.service_category ||
  ''
).toLowerCase();

let serviceCode =
  data.service_details?.selected_service_option ||
  data.selected_service_option ||
  data.service_code ||
  '';

if (!serviceCode) {
  if (serviceCategory.includes('muslim')) serviceCode = 'muslim_marriage';
  else if (serviceCategory.includes('christian')) serviceCode = 'christian_marriage';
  else if (serviceCategory.includes('special')) serviceCode = 'special_marriage';
  else if (serviceCategory.includes('hindu')) serviceCode = 'hindu_marriage';
  else serviceCode = 'muslim_marriage';
}

const leadId =
  data.odoo_lead_id ||
  data.lead_details?.odoo_lead_id ||
  input.odoo_lead_id ||
  '';

const requestNumber =
  data.odoo_request_number ||
  input.odoo_request_number ||
  '';

const descriptionCode =
  input.current_document_code ||
  data.current_document_code ||
  '';

const documentName =
  input.current_document_name ||
  data.current_document_name ||
  '';

return [
  {
    json: {
      lead_id: leadId,
      request_number: requestNumber,
      service_code: serviceCode,
      description_code: descriptionCode,
      document_name: documentName,
      bot_customer_id: input.customer_id || data.bot_customer_id || '',

      is_correction_upload: isCorrectionUpload,

      attachment: {
        filename,
        mimetype,
        data: base64Data
      },

      session_data: input.session_data,

      current_document_index: Number(
        input.current_document_index !== undefined
          ? input.current_document_index
          : data.current_document_index || 0
      ),

      current_document_code: descriptionCode,
      current_document_name: documentName,

      attachment_info: input.attachment_info || `${filename} | ${mimetype}`,
      attachment_file_name: filename,
      attachment_mime_type: mimetype,

      customer_id: input.customer_id,
      channel: input.channel || 'chat',
      language: input.language || 'English'
    }
  }
];

const input = $input.first().json || {};
const body = input.body || input || {};

const correctionItems = Array.isArray(body.correction_items)
  ? body.correction_items
  : [];

const customerId =
  body.bot_customer_id ||
  body.bot_session_id ||
  '';

return [
  {
    json: {
      event: body.event || 'document_correction_required',

      lead_id: body.lead_id || '',
      request_number: body.request_number || '',
      service_code: body.service_code || '',

      customer_id: customerId,
      bot_customer_id: body.bot_customer_id || customerId,
      bot_session_id: body.bot_session_id || customerId,
      channel: body.bot_channel || 'chat',

      correction_items: correctionItems.map((item, index) => ({
        name: item.name || '',
        code: item.description_code || item.code || '',
        description_code: item.description_code || item.code || '',
        reason: item.reason || 'Please upload the correct document.',
        is_data_required: item.is_data_required === true,
        is_attachment_required: item.is_attachment_required !== false,
        status: 'correction_required',
        index
      })),

      received_at: new Date().toISOString()
    }
  }
];

const correction = $('CODE_Normalize_Document_Correction').item.json;
const row = $input.first().json || {};

function parseSession(raw) {
  if (!raw) return {};
  if (typeof raw === 'object') return raw;

  try {
    return JSON.parse(raw);
  } catch (e) {
    return {};
  }
}

const data = parseSession(row.session_data);

const correctionItems = Array.isArray(correction.correction_items)
  ? correction.correction_items
  : [];

const docs = Array.isArray(data.required_documents)
  ? data.required_documents
  : [];

/**
 * Merge correction items into required_documents.
 */
for (const correctionItem of correctionItems) {
  const code = correctionItem.description_code || correctionItem.code || '';

  if (!code) continue;

  const existingIndex = docs.findIndex((doc) => {
    const docCode = doc.code || doc.description_code || '';
    return docCode === code;
  });

  if (existingIndex >= 0) {
    docs[existingIndex] = {
      ...docs[existingIndex],
      name: docs[existingIndex].name || correctionItem.name || code,
      code,
      description_code: code,

      status: 'correction_required',
      correction_required: true,
      correction_reason: correctionItem.reason || 'Please upload the correct document.',
      correction_requested_at: correction.received_at,

      is_data_required: correctionItem.is_data_required === true,
      is_attachment_required: correctionItem.is_attachment_required !== false
    };
  } else {
    docs.push({
      name: correctionItem.name || code,
      code,
      description_code: code,

      is_data_required: correctionItem.is_data_required === true,
      is_attachment_required: correctionItem.is_attachment_required !== false,

