      correction_requested_at: correction.received_at,

      attachment_info: '',
      uploaded_at: '',
      index: docs.length
    });
  }
}

/**
 * Rebuild correction queue from required documents.
 */
const correctionQueue = docs
  .map((doc, index) => ({
    ...doc,
    index
  }))
  .filter((doc) =>
    doc.status === 'correction_required' ||
    doc.correction_required === true ||
    doc.correction_required === 'true'
  );

const firstCorrection = correctionQueue[0];

data.required_documents = docs;
data.correction_queue = correctionQueue;

data.documents_status = firstCorrection ? 'correction_required' : 'pending_verification';
data.documents_collected = false;
data.document_correction_required = !!firstCorrection;

data.current_document_index = firstCorrection
  ? firstCorrection.index
  : data.current_document_index || 0;

data.current_document_code = firstCorrection
  ? firstCorrection.code || firstCorrection.description_code || ''
  : data.current_document_code || '';

data.current_document_name = firstCorrection
  ? firstCorrection.name || ''
  : data.current_document_name || '';

data.correction_event = correction.event || 'document_correction_required';
data.correction_received_at = correction.received_at || new Date().toISOString();

data.odoo_lead_id = correction.lead_id || data.odoo_lead_id || '';
data.odoo_request_number = correction.request_number || data.odoo_request_number || '';
data.service_code = correction.service_code || data.service_code || '';

