function formatDate(dateValue) {
  if (!dateValue) return '';
  const parts = String(dateValue).split('-');
  if (parts.length === 3) {
    return `${parts[2]}/${parts[1]}/${parts[0]}`;
  }
  return String(dateValue);
}

